<?php

namespace App\Support;

use RuntimeException;

/**
 * Catálogo local de los 32 departamentos y 1.104 municipios de Colombia.
 *
 * Se mantiene comprimido para no hacer consultas a servicios externos en
 * cada formulario. La fuente se descomprime una vez por petición y la vista
 * recibe el arreglo ya listo para alimentar los selects dependientes.
 */
final class ColombiaLocations
{
    private const COMPRESSED_DATA = '';

    public static function all(): array
    {
        static $locations = null;

        if ($locations !== null) {
            return $locations;
        }

        $compressed = base64_decode(self::COMPRESSED_DATA, true);
        $json = $compressed === false ? false : gzdecode($compressed);
        $locations = is_string($json) ? json_decode($json, true) : null;

        if (!is_array($locations)) {
            throw new RuntimeException('No fue posible cargar el catálogo de departamentos y municipios de Colombia.');
        }

        return $locations;
    }

    /** @return array<string, array<int, string>> */
    public static function departmentsWithMunicipalities(): array
    {
        $result = [];

        foreach (self::all() as $location) {
            $result[$location['departamento']] = $location['ciudades'];
        }

        return $result;
    }
}
